class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        if n == 1:
            return str(k if k % k == 0 else 8)
        target = int("9" * n)
        for i in range(target, 0, -1):
            if str(i) == str(i)[::-1] and i % k == 0:
                return str(i)
